import {describe, beforeEach, test, expect} from 'vitest';
import {Map, type MapOptions} from '../src/ui/map';
import {beforeMapTest} from '../src/util/test/util';

beforeEach(() => {
    beforeMapTest();
});

describe('Projection mutation bug', () => {
    test('setStyle should not mutate the projection object passed in the style', async () => {
        const map = new Map({container: window.document.createElement('div')} as any as MapOptions);

        // Create a style object with a projection
        const originalStyle = {
            version: 8,
            sources: {},
            layers: [],
            projection: {type: 'globe' as const}
        };

        // Store the original projection reference
        const originalProjection = originalStyle.projection;

        // Set the style
        map.setStyle(originalStyle, {diff: false});
        await map.once('load');

        // Change to mercator
        const mercatorStyle = {
            version: 8,
            sources: {},
            layers: [],
            projection: {type: 'mercator' as const}
        };

        map.setStyle(mercatorStyle, {diff: false});
        await map.once('style.load');

        // The original projection object should not have been mutated
        expect(originalProjection.type).toBe('globe');
    });

    test('setState should not mutate the projection object passed in the style', async () => {
        const map = new Map({container: window.document.createElement('div')} as any as MapOptions);

        const initialStyle = {
            version: 8,
            sources: {},
            layers: []
        };

        map.setStyle(initialStyle, {diff: false});
        await map.once('load');

        // Create a style object with a projection
        const styleWithProjection = {
            version: 8,
            sources: {},
            layers: [],
            projection: {type: 'globe' as const}
        };

        // Store the original projection reference
        const originalProjection = styleWithProjection.projection;

        // Use setState (via setStyle with diff: true)
        map.setStyle(styleWithProjection);
        await map.once('style.load');

        // Change to mercator
        const mercatorStyle = {
            version: 8,
            sources: {},
            layers: [],
            projection: {type: 'mercator' as const}
        };

        map.setStyle(mercatorStyle);
        await map.once('style.load');

        // The original projection object should not have been mutated
        expect(originalProjection.type).toBe('globe');
    });

    test('multiple setStyle calls should not mutate original style objects', async () => {
        const map = new Map({container: window.document.createElement('div')} as any as MapOptions);

        // Create first style with globe projection
        const globeStyle = {
            version: 8,
            sources: {},
            layers: [],
            projection: {type: 'globe' as const}
        };
        const originalGlobeProjection = globeStyle.projection;

        map.setStyle(globeStyle, {diff: false});
        await map.once('load');

        // Create second style with mercator projection
        const mercatorStyle = {
            version: 8,
            sources: {},
            layers: [],
            projection: {type: 'mercator' as const}
        };
        const originalMercatorProjection = mercatorStyle.projection;

        map.setStyle(mercatorStyle, {diff: false});
        await map.once('style.load');

        // Change back to globe
        map.setStyle(globeStyle, {diff: false});
        await map.once('style.load');

        // Both original projection objects should remain unchanged
        expect(originalGlobeProjection.type).toBe('globe');
        expect(originalMercatorProjection.type).toBe('mercator');
    });
});

